class Solution:
    def nextBeautifulNumber(self, n: int) -> int:
        def is_balanced(num):
            num_str = str(num)
            for digit in num_str:
                if num_str.count(digit) != int(digit):
                    return False
            return True

        n += 1
        while not is_balanced(n):
            n += 1
        return n
```
